func (a *AgentNew) executeContextMgmtStep(ctx context.Context) (nextMode ExecutionMode, err error) {

// Flow:
// 1. Determine initial mode (check if context management is needed)
// 2. Loop: execute current mode, get next mode
// 3. Continue until mode is Done or Error
func (a *AgentNew) ExecuteTurn(ctx context.Context, userMessage string) error {
	promptSpan := traceevent.StartSpan(ctx, "prompt", traceevent.CategoryEvent,
		traceevent.Field{Key: "message", Value: userMessage},
	)
	defer promptSpan.End()
	ctx = promptSpan.Context()

	turnSpan := promptSpan.StartChild("turn",
		traceevent.Field{Key: "source", Value: "execute_turn"},
	)
	defer turnSpan.End()
	ctx = turnSpan.Context()

	traceevent.Log(ctx, traceevent.CategoryEvent, "turn_start",
		traceevent.Field{Key: "source", Value: "execute_turn"},
	)

	// Determine initial mode
	mode := a.determineInitialMode(ctx)

	// Trampoline loop
	var userMsgAppended bool
	var resultErr error

	for mode != ModeDone && mode != ModeError {
		switch mode {
		case ModeNormal:
			mode, userMsgAppended, resultErr = a.executeNormalStep(ctx, userMessage, userMsgAppended)

		case ModeContextMgmt:
			mode, resultErr = a.executeContextMgmtStep(ctx)

		default:
			resultErr = fmt.Errorf("unknown execution mode: %s", mode)
			mode = ModeError
		}
	}

	if resultErr != nil {
		traceevent.Log(ctx, traceevent.CategoryEvent, "turn_end",
			traceevent.Field{Key: "status", Value: "error"},
			traceevent.Field{Key: "error", Value: resultErr.Error()},
		)
		return resultErr
	}

	traceevent.Log(ctx, traceevent.CategoryEvent, "turn_end",
		traceevent.Field{Key: "status", Value: "success"},
	)

	return nil
}

// determineInitialMode checks if context management is needed before processing user message.

	return ModeError, fmt.Errorf("failed to append assistant message: %w", err)
}

// Append tool results
for _, result := range toolResults {
	a.snapshot.RecentMessages = append(a.snapshot.RecentMessages, result)
	if err := a.journal.AppendMessage(result); err != nil {
		slog.Warn("[AgentNew] Failed to append tool result", "error", err)
	}
}

// If no tool calls were made, we're done
if len(toolResults) == 0 {
	return ModeDone, nil
}

// Tool calls were made, check if we need context management before next LLM call
shouldTrigger, urgency, _ := a.triggerChecker.ShouldTrigger(a.snapshot)
if shouldTrigger && urgency != agentctx.UrgencySkip {
	slog.Info("[AgentNew] Context management needed during conversation loop",
		"urgency", urgency,
		"cycle", cycle+1,
	)
	return ModeContextMgmt, nil
}

// Continue the loop to get the final response
slog.Info("[AgentNew] Tool calls completed, continuing conversation",
	"tool_count", len(toolResults),
	"cycle", cycle+1,
)

package context

import "fmt"

// TriggerChecker evaluates trigger conditions.
type TriggerChecker struct {
	// Configuration (use constants from trigger_config.go)
	IntervalTurns int
	MinTurns      int
	TokenThreshold float64
	TokenUrgent    float64
	StaleCount     int
	MinInterval    int
}

// NewTriggerChecker creates a new TriggerChecker with default config.
func NewTriggerChecker() *TriggerChecker {
	return &TriggerChecker{
		IntervalTurns:  IntervalTurns,
		MinTurns:       MinTurns,
		TokenThreshold: TokenThreshold,
		TokenUrgent:    TokenUrgent,
		StaleCount:     StaleCount,
		MinInterval:    MinInterval,
	}
}

// NewTriggerCheckerWithConfig creates a TriggerChecker with custom config (for testing).
func NewTriggerCheckerWithConfig(config TriggerConfig) *TriggerChecker {
	return &TriggerChecker{
		IntervalTurns:  config.IntervalTurns,
		MinTurns:       config.MinTurns,
		TokenThreshold: config.TokenThreshold,
		TokenUrgent:    config.TokenUrgent,
		StaleCount:     config.StaleCount,
		MinInterval:    config.MinInterval,
	}
}

// TriggerConfig allows custom trigger configuration.
type TriggerConfig struct {
	IntervalTurns  int
	MinTurns       int
	TokenThreshold float64
	TokenUrgent    float64
	StaleCount     int
	MinInterval    int
}

// ShouldTrigger checks if context management should be triggered.
// Returns (shouldTrigger, urgency, reason).
func (t *TriggerChecker) ShouldTrigger(snapshot *ContextSnapshot) (bool, string, string) {
	if snapshot == nil {
		return false, "", "no_snapshot"
	}

	state := snapshot.AgentState

	// 1. Check minimum turn requirement
	if state.TotalTurns < t.MinTurns {
		return false, "", "below_min_turns"
	}

	tokenPercent := snapshot.EstimateTokenPercent()
	staleCount := snapshot.CountStaleOutputs(10) // Count outputs with stale >= 10

	// 2. URGENT mode: token usage critical - ignore minInterval
	if tokenPercent >= t.TokenUrgent {
		return true, UrgencyUrgent, fmt.Sprintf("token_usage_%.0f%%", tokenPercent*100)
	}

	// 3. Check minimum interval for normal triggers
	if state.TurnsSinceLastTrigger < t.MinInterval {
		return false, "", "within_min_interval"
	}

	// 4. Normal trigger conditions
	if tokenPercent >= t.TokenThreshold && staleCount >= 10 {
		return true, UrgencyNormal, "token_and_stale_threshold"
	}

	if tokenPercent >= 0.30 {
		return true, UrgencyNormal, fmt.Sprintf("token_usage_%.0f%%", tokenPercent*100)
	}

	if state.TotalTurns >= 15 && tokenPercent >= 0.25 {
		return true, UrgencyNormal, "periodic_token_check"
	}

	if staleCount >= t.StaleCount {
		return true, UrgencyNormal, fmt.Sprintf("stale_outputs_%d", staleCount)
	}

	// 5. Skip condition: context is healthy
	if state.TotalTurns >= 20 && tokenPercent < 0.30 {
		return false, UrgencySkip, "context_healthy"
	}

	// 6. Periodic check
	if state.TotalTurns%t.IntervalTurns == 0 {
		return true, UrgencyPeriodic, "periodic_check"
	}

	return false, "", "no_trigger"
}

// Trigger urgency levels.
const (
	UrgencyNone     = ""
	UrgencyUrgent   = "urgent"   // Ignores minInterval
	UrgencyNormal   = "normal"   // Standard trigger
	UrgencyPeriodic = "periodic" // Routine check
	UrgencySkip     = "skip"     // Context is healthy, skip
)

